import React from "react";
import { Row, Col } from "antd";
import { Button } from "semantic-ui-react";
import { NavLink, Switch, Route } from "react-router-dom";
import { useAISmartTroubleShootingPageHooks } from "./AISmartTroubleshooting-page-hooks";
import CorrectiveMaintenancePage from "./components/corrective-maintenance-page/corrective-maintenance-page";
import PreventiveMaintenancePage from "./components/preventive-maintenance-page/preventive-maintenance-page";

const AISmartTroubleShootingPage = () => {
  useAISmartTroubleShootingPageHooks();
  return (
    <Switch>
      <Route path="/smart-troubleshooting/ai-smart-troubleshooting" exact>
        <OptionsPage />
      </Route>
      <Route
        path="/smart-troubleshooting/ai-smart-troubleshooting/corrective-maintenance-page"
        exact
      >
        <CorrectiveMaintenancePage />
      </Route>
      <Route
        path="/smart-troubleshooting/ai-smart-troubleshooting/preventive-maintenance-page"
        exact
      >
        <PreventiveMaintenancePage />
      </Route>
    </Switch>
  );
};

const OptionsPage = () => {
  return (
    <div
      style={{
        paddingTop: "3%",
        display: "grid",
        gridTemplateColumns: "1fr 1fr",
        gridTemplateRows: "1fr",
      }}
    >
      <Row>
        <div
          style={{
            fontSize: "3vh",
            fontWeight: "bold",
            fontFamily: "Lato",
            marginBottom: "5vh",
            marginLeft: "22vw",
          }}
        >
          Preventive Maintenance
        </div>
        <Button
          as={NavLink}
          to="/smart-troubleshooting/ai-smart-troubleshooting/preventive-maintenance-page"
          content="Preventive Maintenance"
          style={{
            fontSize: "2vmin",
            // padding: "10vh",
            verticalAlign: "middle",
            textAlign: "center",
            marginBottom: "1vh",
            marginLeft: "30vh",
            width: "20vw",
            height: "40vh",
            lineHeight: "3vmin",
            boxShadow: "5px 5px #a9a9a9",
          }}
        />
      </Row>
      <Row>
        <div
          style={{
            fontSize: "3vh",
            fontWeight: "bold",
            fontFamily: "Lato",
            marginBottom: "5vh",
            marginRight: "22vw",
          }}
        >
          Corrective Maintenance
        </div>
        <Col>
          <Button
            as={NavLink}
            to="/smart-troubleshooting/ai-smart-troubleshooting/corrective-maintenance-page"
            content="Create A New Record"
            style={{
              fontSize: "2vmin",
              // padding: "10vh",
              verticalAlign: "bottom",
              textAlign: "center",
              marginBottom: "1vh",
              marginRight: "30vh",
              width: "20vw",
              height: "20vh",
              lineHeight: "3vmin",
              boxShadow: "5px 5px #a9a9a9",
            }}
          />
        </Col>
        <Col>
          <Button
            // as={NavLink}
            // to="/smart-troubleshooting/smart-om-manual"
            content="Continue from Saved Records"
            style={{
              fontSize: "2vmin",
              // padding: "10vh",
              verticalAlign: "middle",
              textAlign: "center",
              marginBottom: "1vh",
              marginRight: "30vh",
              width: "20vw",
              height: "20vh",
              lineHeight: "3vmin",
              boxShadow: "5px 5px #a9a9a9",
            }}
          />
        </Col>
      </Row>
    </div>
  );
};

export default AISmartTroubleShootingPage;
